function checkPrime(arr) {
    // Check for invalid input
    if (arr.length < 2) return;

    // Initialize a counter for the number of primes found
    let count = 0;

    // Loop over the array
    arr.forEach(num => {

        // Check each element for primality
        if (isPrime(num)) {
            count++;
        }
    });

    // Return the number of primes found
    return count;
}

